return [{
  json: {
    from: 'angry@customer.com',
    subject: 'URGENT: System is down!!!',
    body: 'This is completely unacceptable. We've been down for 2 hours and no one has responded. This is costing us thousands of dollars. I need this fixed IMMEDIATELY or we're canceling our contract.',
    receivedAt: new Date().toISOString()
  }
}];

const email = $input.first().json;
const body = email.body.toLowerCase();
const subject = email.subject.toLowerCase();

// Sentiment analysis
let urgency = 'low';
let sentiment = 'neutral';

// Urgency keywords
const urgentWords = ['urgent', 'down', 'broken', 'immediately', 'asap', 'critical', 'emergency'];
const angryWords = ['unacceptable', 'cancel', 'refund', 'terrible', 'worst', 'ridiculous'];

urgentWords.forEach(word => {
  if (body.includes(word) || subject.includes(word)) urgency = 'high';
});

angryWords.forEach(word => {
  if (body.includes(word)) sentiment = 'angry';
});

// Category detection
let category = 'general';
if (body.includes('login') || body.includes('password') || body.includes('access')) category = 'access';
if (body.includes('payment') || body.includes('billing') || body.includes('invoice')) category = 'billing';
if (body.includes('bug') || body.includes('error') || body.includes('crash')) category = 'technical';
if (body.includes('feature') || body.includes('request') || body.includes('add')) category = 'feature';

return [{
  json: {
    ...email,
    urgency,
    sentiment,
    category,
    needsHuman: urgency === 'high' || sentiment === 'angry'
  }
}];

