// Search knowledge base (mock)
const kb = {
  'password': 'Reset your password here: [link]',
  'login': 'Having trouble logging in? Try clearing cookies.',
  'billing': 'View and update billing: [link]',
  'api': 'API documentation: [link]'
};

const body = $input.first().json.body.toLowerCase();
let suggestion = null;

for (const [keyword, response] of Object.entries(kb)) {
  if (body.includes(keyword)) {
    suggestion = response;
    break;
  }
}

return [{
  json: {
    ...$input.first().json,
    kbSuggestion: suggestion
  }
}];
